import { html, customElement, } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import type { PreValueSourceTypeWithSettings } from "@umbraco-forms/generated";
import { FormsDataSourceTypeCollectionRepository } from '../../../../provider-types/datasource-types/repository/collection/index.js';
import type { FormsDataSourceCreateOptionsModalData } from './index.js';

const elementName = 'forms-datasource-create-options-modal';

@customElement(elementName)
export class FormsDataSourceCreateOptionsModalElement extends UmbModalBaseElement<FormsDataSourceCreateOptionsModalData> {

	#dataSourceTypes: Array<PreValueSourceTypeWithSettings> = [];

	constructor() {
    super();

    this.#initialize();
  }

	async #initialize() {
    const repository = new FormsDataSourceTypeCollectionRepository(this);
    const { data } = await repository.requestCollection();
    this.#dataSourceTypes = data?.items || [];
    this.requestUpdate();
  }

  #onClick(id: string) {
    const href = `section/forms/workspace/datasource/create/${id}`;
    window.history.pushState({}, "", href);
    this._submitModal();
  }

  render() {
    return html`<umb-body-layout headline=${this.localize.term("formDataSources_chooseDatasourceType")}>
        <uui-box>
          <uui-ref-list>
            ${this.#dataSourceTypes.map(
              (dataSourceType) =>
                html`<umb-ref-item
                  selectable
                  .name=${dataSourceType.name}
                  .detail=${dataSourceType.description}
                  .icon=${dataSourceType.icon}
                  @click=${() => this.#onClick(dataSourceType.id)}
                >
                </umb-ref-item>`
            )}
          </uui-ref-list>
        </uui-box>
        <uui-button
          slot="actions"
          label=${this.localize.term("general_cancel")}
          @click=${this._rejectModal}
        ></uui-button>
      </umb-body-layout>`;
  }
}

export default FormsDataSourceCreateOptionsModalElement;

declare global {
	interface HTMLElementTagNameMap {
		[elementName]: FormsDataSourceCreateOptionsModalElement;
	}
}
